body.script:
(async function() {
  const ns = 'http://www.w3.org/1999/xhtml';
  const body = document.querySelector('body');
  const head = document.createElementNS(ns, 'head');
  body.prepend(head);

  // ARSENIC CONFIGURATION
  // We point these to the official Arsenic repository files
  const base = 'https://cdn.jsdelivr.net/gh/smartfoloo/arsenic@main/';

  async function loadHtmlContent() {
    try {
      const response = await fetch(base + 'index.html');
      const text = await response.text();
      const parser = new DOMParser();
      const doc = parser.parseFromString(text, 'text/html');
      const root = document.getElementById('root');
      if (doc.body) {
        root.innerHTML = doc.body.innerHTML;
      }
    } catch (err) {
      console.error('Failed to load Arsenic HTML:', err);
    }
  }

  async function appendHeadNode(nodeDef) {
    const node = document.createElement(nodeDef.tag);
    for (const [name, value] of Object.entries(nodeDef.attrs)) {
      node.setAttribute(name, value);
    }
    head.appendChild(node);
    if (nodeDef.tag === 'script' && nodeDef.attrs.src) {
      await new Promise((res) => { node.onload = res; node.onerror = res; });
    }
  }

  const headNodes = [
    { tag: 'link', attrs: { rel: 'stylesheet', href: base + 'style.css' } },
    { tag: 'script', attrs: { src: base + 'index.js' } }
  ];

  await loadHtmlContent();
  for (const nodeDef of headNodes) {
    await appendHeadNode(nodeDef);
  }
})();
